 1→import { distanceToSegment } from './line';
 2→import { add, distance, midpoint, normalize, perpendicular, scale, subtract } from './point';
 3→
 4→const EPSILON = 1e-6;
 5→
 6→export function sectionCutLength(sectionCut) {
 7→  return distance(sectionCut?.startPoint || { x: 0, y: 0 }, sectionCut?.endPoint || { x: 0, y: 0 });
 8→}
 9→
10→export function sectionCutAxis(sectionCut) {
11→  return normalize(subtract(sectionCut?.endPoint || { x: 0, y: 0 }, sectionCut?.startPoint || { x: 0, y: 0 }));
12→}
13→
14→export function sectionCutNormal(sectionCut) {
15→  const axis = sectionCutAxis(sectionCut);
16→  const direction = sectionCut?.direction === -1 ? -1 : 1;
17→  return scale(perpendicular(axis), direction);
18→}
19→
20→export function sectionCutViewAxis(sectionCut) {
21→  const normal = sectionCutNormal(sectionCut);
22→  return { x: -normal.y, y: normal.x };
23→}
24→
25→export function projectPointToSectionCut(sectionCut, point) {
26→  const origin = sectionCut?.startPoint || { x: 0, y: 0 };
27→  const relative = subtract(point, origin);
28→  const normal = sectionCutNormal(sectionCut);
29→  const viewAxis = sectionCutViewAxis(sectionCut);
30→  const start = sectionCut?.startPoint || { x: 0, y: 0 };
31→  const end = sectionCut?.endPoint || { x: 0, y: 0 };
32→  const startAlong = start.x * viewAxis.x + start.y * viewAxis.y;
33→  const endAlong = end.x * viewAxis.x + end.y * viewAxis.y;
34→  const pointAlong = point.x * viewAxis.x + point.y * viewAxis.y;
35→  const minAlong = Math.min(startAlong, endAlong);
36→
37→  return {
38→    along: pointAlong - minAlong,
39→    offset: relative.x * normal.x + relative.y * normal.y,
40→  };
41→}
42→
43→export function sectionCutArrow(sectionCut) {
44→  const axis = sectionCutAxis(sectionCut);
45→  if (Math.abs(axis.x) < EPSILON && Math.abs(axis.y) < EPSILON) return null;
46→
47→  const normal = sectionCutNormal(sectionCut);
48→  const center = midpoint(sectionCut.startPoint, sectionCut.endPoint);
49→  const shaftStart = add(center, scale(normal, 100));
50→  const shaftEnd = add(center, scale(normal, 450));
51→  const headBase = add(shaftEnd, scale(normal, -120));
52→  const headNormal = scale(axis, 90);
53→
54→  return {
55→    shaftStart,
56→    shaftEnd,
57→    headA: add(headBase, headNormal),
58→    headB: add(headBase, scale(headNormal, -1)),
59→  };
60→}
61→
62→export function getSectionCutRenderData(sectionCut) {
63→  if (!sectionCut || sectionCutLength(sectionCut) < EPSILON) return null;
64→
65→  return {
66→    line: {
67→      start: sectionCut.startPoint,
68→      end: sectionCut.endPoint,
69→    },
70→    arrow: sectionCutArrow(sectionCut),
71→    center: midpoint(sectionCut.startPoint, sectionCut.endPoint),
72→    length: sectionCutLength(sectionCut),
73→    label: sectionCut.label || 'Section',
74→  };
75→}
76→
77→export function hitTestSectionCut(point, sectionCut, tolerance) {
78→  if (!sectionCut) return false;
79→  return distanceToSegment(point, sectionCut.startPoint, sectionCut.endPoint) <= tolerance;
80→}
