 11→const EPSILON = 1e-6;
 12→
 13→function clamp(value, min, max) {
 14→  return Math.max(min, Math.min(max, value));
 15→}
 16→
 17→function uniqueSortedValues(values = []) {
 18→  const sorted = [...values].sort((a, b) => a - b);
 19→  return sorted.filter((value, index) => (
 20→    index === 0 || Math.abs(value - sorted[index - 1]) > 1e-4
 21→  ));
 22→}
 23→
 24→function intervalFromValues(values, maxLength) {
 25→  if (!values.length) return null;
 26→  const clamped = values
 27→    .map((value) => clamp(value, 0, maxLength))
 28→    .filter((value) => value >= -EPSILON && value <= maxLength + EPSILON);
 29→  if (!clamped.length) return null;
 30→
 31→  const left = Math.min(...clamped);
 32→  const right = Math.max(...clamped);
 33→  if (right - left < EPSILON) return null;
 34→  return { left, right };
 35→}
 36→
 37→function projectPolygon(sectionCut, polygon = []) {
 38→  return polygon.map((point) => projectPointToSectionCut(sectionCut, point));
 39→}
 40→
 41→function polygonCutInterval(sectionCut, polygon = []) {
 42→  if (polygon.length < 3) return null;
 43→
 44→  const values = [];
 45→  for (let index = 0; index < polygon.length; index += 1) {
 46→    const start = polygon[index];
 47→    const end = polygon[(index + 1) % polygon.length];
 48→    const hit = segmentIntersection(sectionCut.startPoint, sectionCut.endPoint, start, end);
 49→    if (hit) {
 50→      values.push(projectPointToSectionCut(sectionCut, hit).along);
 51→    }
 52→  }
 53→
 54→  if (pointInPolygon(sectionCut.startPoint, polygon)) values.push(0);
 55→  if (pointInPolygon(sectionCut.endPoint, polygon)) values.push(sectionCutLength(sectionCut));
 56→
 57→  return intervalFromValues(uniqueSortedValues(values), sectionCutLength(sectionCut));
 58→}
 59→
 60→function polygonProjectionInfo(sectionCut, polygon = [], depth) {
 61→  if (polygon.length < 3) return null;
 62→  const projected = projectPolygon(sectionCut, polygon);
 63→  const alongs = projected.map((entry) => entry.along);
 64→  const offsets = projected.map((entry) => entry.offset);
 65→  const minOffset = Math.min(...offsets);
 66→  const maxOffset = Math.max(...offsets);
 67→
 68→  if (maxOffset < -EPSILON || minOffset > depth + EPSILON) return null;
 69→
 70→  return {
 71→    interval: intervalFromValues(alongs, sectionCutLength(sectionCut)),
 72→    depth: offsets.reduce((sum, value) => sum + Math.max(0, value), 0) / Math.max(1, offsets.length),
 73→    minOffset,
 74→    maxOffset,
 75→  };
 76→}
 77→
 78→function createSceneRect(id, category, renderMode, interval, bottom, top, depth, sourceId) {
 79→  if (!interval) return null;
 80→  if (interval.right - interval.left < EPSILON) return null;
 81→  if (Math.abs(top - bottom) < EPSILON) return null;
 82→
 83→  return {
 84→    id,
 85→    category,
 86→    renderMode,
 87→    left: interval.left,
 88→    right: interval.right,
 89→    bottom,
 90→    top,
 91→    depth,
 92→    sourceId,
 93→  };
 94→}
 95→
 96→function createFootprintRect(id, category, sourceId, sectionCut, polygon, bottom, top, depthLimit) {
 97→  const cutInterval = polygonCutInterval(sectionCut, polygon);
 98→  if (cutInterval) {
 99→    return createSceneRect(id, category, 'cut', cutInterval, bottom, top, 0, sourceId);
100→  }
101→
102→  const projection = polygonProjectionInfo(sectionCut, polygon, depthLimit);
103→  if (!projection?.interval) return null;
104→  return createSceneRect(id, category, 'projection', projection.interval, bottom, top, projection.depth, sourceId);
105→}
