 3→function mergeBounds(current, next) {
 4→  if (!next) return current;
 5→  if (!current) return { ...next };
 6→
 7→  return {
 8→    minX: Math.min(current.minX, next.minX),
 9→    maxX: Math.max(current.maxX, next.maxX),
10→    minY: Math.min(current.minY, next.minY),
11→    maxY: Math.max(current.maxY, next.maxY),
12→    minElevation: Math.min(current.minElevation, next.minElevation),
13→    maxElevation: Math.max(current.maxElevation, next.maxElevation),
14→  };
